INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Alternate_Heel_Touchers','Alternate Heel Touchers','abdominales',ARRAY[]::text[],'peso corporal','strength',ARRAY['Lie on the floor with the knees bent and the feet on the floor around 18-24 inches apart. Your arms should be extended by your side. This will be your starting position.','Crunch over your torso forward and up about 3-4 inches to the right side and touch your right heel as you hold the contraction for a second. Exhale while performing this movement.','Now go back slowly to the starting position as you inhale.','Now crunch over your torso forward and up around 3-4 inches to the left side and touch your left heel as you hold the contraction for a second. Exhale while performing this movement and then go back to the starting position as you inhale. Now that both heels have been touched, that is considered 1 repetition.','Continue alternating sides in this manner until all prescribed repetitions are done.'],'Lie on the floor with the knees bent and the feet on the floor around 18-24 inches apart. Your arms should be extended by your side. This will be your starting position. Crunch over your torso forward and up about 3-4 inches to the right side and touch your right heel as you hold the contraction for a second. Exhale while performing this movement. Now go back slowly to the starting position as you inhale. Now crunch over your torso forward and up around 3-4 inches to the left side and touch your left heel as you hold the contraction for a second. Exhale while performing this movement and then go back to the starting position as you inhale. Now that both heels have been touched, that is considered 1 repetition. Continue alternating sides in this manner until all prescribed repetitions are done.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Heel_Touchers/0.jpg','exercisedb',true),('Alternate_Incline_Dumbbell_Curl','Alternate Incline Dumbbell Curl','bíceps',ARRAY['antebrazos'],'mancuernas','strength',ARRAY['Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position.','While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.','Slowly begin to bring the dumbbell back to starting position as your breathe in.','Repeat the movement with the left hand. This equals one repetition.','Continue alternating in this manner for the recommended amount of repetitions.'],'Sit down on an incline bench with a dumbbell in each hand being held at arms length. Tip: Keep the elbows close to the torso.This will be your starting position. While holding the upper arm stationary, curl the right weight forward while contracting the biceps as you breathe out. As you do so, rotate the hand so that the palm is facing up. Continue the movement until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move. Slowly begin to bring the dumbbell back to starting position as your breathe in. Repeat the movement with the left hand. This equals one repetition. Continue alternating in this manner for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Incline_Dumbbell_Curl/0.jpg','exercisedb',true),('Alternate_Leg_Diagonal_Bound','Alternate Leg Diagonal Bound','cuádriceps',ARRAY['abductores','aductores','pantorrillas','glúteos','isquiotibiales'],NULL,'plyometrics',ARRAY['Assume a comfortable stance with one foot slightly in front of the other.','Begin by pushing off with the front leg, driving the opposite knee forward and as high as possible before landing. Attempt to cover as much distance to each side with each bound.','It may help to use a line on the ground to guage distance from side to side.','Repeat the sequence with the other leg.'],'Assume a comfortable stance with one foot slightly in front of the other. Begin by pushing off with the front leg, driving the opposite knee forward and as high as possible before landing. Attempt to cover as much distance to each side with each bound. It may help to use a line on the ground to guage distance from side to side. Repeat the sequence with the other leg.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternate_Leg_Diagonal_Bound/0.jpg','exercisedb',true),('Alternating_Cable_Shoulder_Press','Alternating Cable Shoulder Press','hombros',ARRAY['tríceps'],'cable','strength',ARRAY['Move the cables to the bottom of the tower and select an appropriate weight.','Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.','Keeping your head and chest up, extend through the elbow to press one side directly over head.','After pausing at the top, return to the starting position and repeat on the opposite side.'],'Move the cables to the bottom of the tower and select an appropriate weight. Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position. Keeping your head and chest up, extend through the elbow to press one side directly over head. After pausing at the top, return to the starting position and repeat on the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Cable_Shoulder_Press/0.jpg','exercisedb',true),('Alternating_Deltoid_Raise','Alternating Deltoid Raise','hombros',ARRAY[]::text[],'mancuernas','strength',ARRAY['In a standing position, hold a pair of dumbbells at your side.','Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating.','Return the weights to your side.','On the next repetition, raise the weights laterally, raising them out to your side to about shoulder height.','Return the weights to the starting position and continue alternating to the front and side.'],'In a standing position, hold a pair of dumbbells at your side. Keeping your elbows slightly bent, raise the weights directly in front of you to shoulder height, avoiding any swinging or cheating. Return the weights to your side. On the next repetition, raise the weights laterally, raising them out to your side to about shoulder height. Return the weights to the starting position and continue alternating to the front and side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Deltoid_Raise/0.jpg','exercisedb',true),('Alternating_Floor_Press','Alternating Floor Press','pecho',ARRAY['abdominales','hombros','tríceps'],'kettlebells','strength',ARRAY['Lie on the floor with two kettlebells next to your shoulders.','Position one in place on your chest and then the other, gripping the kettlebells on the handle with the palms facing forward.','Extend both arms, so that the kettlebells are being held above your chest. Lower one kettlebell, bringing it to your chest and turn the wrist in the direction of the locked out kettlebell.','Raise the kettlebell and repeat on the opposite side.'],'Lie on the floor with two kettlebells next to your shoulders. Position one in place on your chest and then the other, gripping the kettlebells on the handle with the palms facing forward. Extend both arms, so that the kettlebells are being held above your chest. Lower one kettlebell, bringing it to your chest and turn the wrist in the direction of the locked out kettlebell. Raise the kettlebell and repeat on the opposite side.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Floor_Press/0.jpg','exercisedb',true),('Alternating_Hang_Clean','Alternating Hang Clean','isquiotibiales',ARRAY['bíceps','pantorrillas','antebrazos','glúteos','espalda baja','trapecios'],'kettlebells','strength',ARRAY['Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean one kettlebell to your shoulder and hold on to the other kettlebell in a hanging position. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so.','Lower the cleaned kettlebell to a hanging position and clean the alternate kettlebell. Repeat.'],'Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead. Clean one kettlebell to your shoulder and hold on to the other kettlebell in a hanging position. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so. Lower the cleaned kettlebell to a hanging position and clean the alternate kettlebell. Repeat.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Hang_Clean/0.jpg','exercisedb',true),('Alternating_Kettlebell_Press','Alternating Kettlebell Press','hombros',ARRAY['tríceps'],'kettlebells','strength',ARRAY['Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so.','Press one directly overhead by extending through the elbow, turning it so the palm faces forward while holding the other kettlebell stationary .','Lower the pressed kettlebell to the starting position and immediately press with your other arm.'],'Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so. Press one directly overhead by extending through the elbow, turning it so the palm faces forward while holding the other kettlebell stationary . Lower the pressed kettlebell to the starting position and immediately press with your other arm.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Press/0.jpg','exercisedb',true),('Alternating_Kettlebell_Row','Alternating Kettlebell Row','espalda media',ARRAY['bíceps','dorsales'],'kettlebells','strength',ARRAY['Place two kettlebells in front of your feet. Bend your knees slightly and push your butt out as much as possible. As you bend over to get into the starting position grab both kettlebells by the handles.','Pull one kettlebell off of the floor while holding on to the other kettlebell. Retract the shoulder blade of the working side, as you flex the elbow, drawing the kettlebell towards your stomach or rib cage.','Lower the kettlebell in the working arm and repeat with your other arm.'],'Place two kettlebells in front of your feet. Bend your knees slightly and push your butt out as much as possible. As you bend over to get into the starting position grab both kettlebells by the handles. Pull one kettlebell off of the floor while holding on to the other kettlebell. Retract the shoulder blade of the working side, as you flex the elbow, drawing the kettlebell towards your stomach or rib cage. Lower the kettlebell in the working arm and repeat with your other arm.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Kettlebell_Row/0.jpg','exercisedb',true),('Alternating_Renegade_Row','Alternating Renegade Row','espalda media',ARRAY['abdominales','bíceps','pecho','dorsales','tríceps'],'kettlebells','strength',ARRAY['Place two kettlebells on the floor about shoulder width apart. Position yourself on your toes and your hands as though you were doing a pushup, with the body straight and extended. Use the handles of the kettlebells to support your upper body. You may need to position your feet wide for support.','Push one kettlebell into the floor and row the other kettlebell, retracting the shoulder blade of the working side as you flex the elbow, pulling it to your side.','Then lower the kettlebell to the floor and begin the kettlebell in the opposite hand. Repeat for several reps.'],'Place two kettlebells on the floor about shoulder width apart. Position yourself on your toes and your hands as though you were doing a pushup, with the body straight and extended. Use the handles of the kettlebells to support your upper body. You may need to position your feet wide for support. Push one kettlebell into the floor and row the other kettlebell, retracting the shoulder blade of the working side as you flex the elbow, pulling it to your side. Then lower the kettlebell to the floor and begin the kettlebell in the opposite hand. Repeat for several reps.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Alternating_Renegade_Row/0.jpg','exercisedb',true);